  ('352b67f7-34e6-5391-9bb0-b82019389bf4', 'e4de2955-978a-53c2-8e40-d3f9c10cb570', 'fa', 'اول، نخستین', 'این اولین بار است که به تهران می‌روم.'),
  ('a5e2b150-3aa4-5550-a475-bc0a642a9cfe', '5c04f8bb-0244-5d99-920d-9c60f3453679', 'fa', 'اول، یکم', 'فصل اول کتاب بسیار جالب است.'),
  ('55a10816-62e8-50c4-9b7b-b4d60d1284d5', 'dd7bfcf0-26fb-5b4a-90e1-982220d5bf81', 'fa', 'ابتدا، در ابتدا', 'اول باید دست‌هایت را بشویی.'),
  ('a8260dd2-c23c-511f-8aac-5fd30e0b7799', 'db298aa3-b3cc-5289-bad8-91de275dd0f9', 'fa', 'بار اول', 'بار اول بود که او را دیدم.'),
  ('c194775a-f8f4-5aff-b4bc-3ea912f8e8de', 'b132d144-098f-5b10-a03d-ff6f35a0c40f', 'fa', 'دانستن، آگاه بودن از', 'من نمی‌دانم او کجا رفته است.'),
  ('5b77ce23-ac00-560e-89cc-0700d6b3049b', 'ba19312c-b541-5e4a-9507-3e35824e0411', 'fa', 'بلد بودن، توانایی داشتن', 'او بلد است که شنا کند.'),
  ('54dee202-50e9-56a1-9429-84f29c4a732a', '8cf44e55-f95c-5b1c-9fd9-c9bf9976fae3', 'fa', 'دیدن', 'من از پنجره درختها را می‌دیدم.'),
  ('83dcad4f-fc47-58c0-94e2-a0fc794b18b3', '8c0b5344-499e-567e-b726-2b173111b4da', 'fa', 'فهمیدن', 'حالا می‌فهمم که چرا او این کار را کرد.'),
