  ('55442497-fa4a-5ee8-b21a-ddf4f3b55e5f', 'c3a26473-5275-503f-be19-d262274a1627', 'fa', 'پشت (طرف عقب)', 'نام نویسنده روی پشت کتاب نوشته شده است.'),
