  ('973a2de5-123d-5887-8f86-ee67326760c1', '2223bf46-2479-5260-b396-b23c78ea8388', 'fa', 'به عقب', 'یک قدم به عقب برداشت.'),
  ('52d0e47f-1cde-5d5f-bc54-3622605efedf', 'b5e73723-4daf-5db3-94e5-9db92d0384e5', 'fa', 'خواستن، تمایل داشتن', 'من می‌خواهم یک فنجان چای بخورم.'),
