  ('ece5b765-5a26-51d9-8947-536bec3ce3d3', 'da8c12ac-e531-59a6-b908-6ba9289dbb8c', 'fa', 'رفتن، حرکت کردن', 'من هر روز به مدرسه می‌روم.'),
  ('35e93da0-2587-5eef-98ed-4da442a8bf80', '58794477-2cf6-54f5-8e27-fe875ff37086', 'fa', 'پیش رفتن، ادامه دادن', 'ما با برنامه‌ای که تعیین کردیم پیش می‌رویم.'),
